import torch
from flask import Flask, request, jsonify
from torchvision import models
from PIL import Image
import io

app = Flask(__name__)

# Load a pre-trained model (e.g., ResNet)
model = models.resnet18(pretrained=True)
model.eval()

@app.route('/predict', methods=['POST'])
def predict():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    
    image = Image.open(io.BytesIO(file.read()))
    input_tensor = preprocess(image)
    input_batch = input_tensor.unsqueeze(0)  # Add a batch dimension

    with torch.no_grad():
        output = model(input_batch)
    
    probabilities = torch.nn.functional.softmax(output[0], dim=0)
    _, indices = torch.sort(probabilities, descending=True)

    predicted_idx = indices[0].item()
    confidence_score = probabilities[predicted_idx].item()

    return jsonify({
        'predicted_class': idx_to_label(predicted_idx),
        'confidence_score': float(confidence_score)
    })

